import React, { useState, useEffect, useRef } from 'react';
import { TextField, IconButton, InputAdornment } from '@mui/material';
import { Language } from '@mui/icons-material';
import { enablePramukhIME, disablePramukhIME } from '../utils/tamilTransliteration';

const TranslatableTextField = ({ label, value, onChange, helperText, ...props }) => {
  const [tamilEnabled, setTamilEnabled] = useState(false); // Default to English (disabled)
  const inputRef = useRef(null);

  useEffect(() => {
    // Small delay to ensure ref is set and element is in DOM
    const timer = setTimeout(() => {
      if (inputRef.current) {
        // Material-UI's inputRef should point to input, but verify
        let actualInput = inputRef.current;
        
        // If it's not an input element, find the input inside
        if (actualInput.tagName !== 'INPUT') {
          actualInput = actualInput.querySelector?.('input') || actualInput;
        }
        
        // Verify it's an input element (has setSelectionRange method)
        if (actualInput && typeof actualInput.setSelectionRange === 'function') {
          if (tamilEnabled) {
            console.log('Enabling IME on input element:', actualInput);
            enablePramukhIME(actualInput);
          } else {
            console.log('Disabling IME on input element:', actualInput);
            disablePramukhIME(actualInput);
          }
        } else {
          console.warn('Element is not a valid input:', actualInput, 'Has setSelectionRange:', typeof actualInput?.setSelectionRange);
        }
      }
    }, 100);
    
    return () => clearTimeout(timer);
  }, [tamilEnabled]);

  const toggleTamil = () => {
    // Sync current value before toggling to ensure value persistence
    if (inputRef.current) {
      let actualInput = inputRef.current;
      if (actualInput.tagName !== 'INPUT') {
        actualInput = actualInput.querySelector?.('input') || actualInput;
      }
      if (actualInput && actualInput.value !== value && onChange) {
        // Update React state with current input value
        onChange({ target: { value: actualInput.value } });
      }
    }
    setTamilEnabled(!tamilEnabled);
  };

  const handleFocus = (e) => {
    // Re-enable/disable PramukhIME when field gains focus based on current state
    const actualInput = e.target;
    if (actualInput && typeof actualInput.setSelectionRange === 'function') {
      setTimeout(() => {
        if (tamilEnabled) {
          enablePramukhIME(actualInput);
        } else {
          disablePramukhIME(actualInput);
        }
      }, 50);
    }
  };

  const handleBlur = (e) => {
    // Sync the final value with React state after PramukhIME has processed it
    // This ensures values persist when switching fields or toggling translation
    const finalValue = e.target.value;
    if (finalValue !== value && onChange) {
      // Create a synthetic event to update React state
      onChange({ target: { value: finalValue } });
    }
  };

  return (
    <TextField
      inputRef={inputRef}
      label={label}
      value={value}
      onChange={onChange}
      onFocus={handleFocus}
      onBlur={handleBlur}
      fullWidth
      helperText={helperText || (tamilEnabled ? 'தமிழ் பிழையுணர்தல் செயல்படுத்தப்பட்டது' : 'ஐகானைக் கிளிக் செய்து தமிழ் பிழையுணர்தலை இயக்கவும்')}
      InputProps={{
        endAdornment: (
          <InputAdornment position="end">
            <IconButton
              onClick={toggleTamil}
              color={tamilEnabled ? 'primary' : 'default'}
              edge="end"
            >
              <Language />
            </IconButton>
          </InputAdornment>
        ),
      }}
      sx={{
        '& .MuiOutlinedInput-root': {
          '&.Mui-focused fieldset': {
            borderColor: tamilEnabled ? '#1976d2' : undefined,
            borderWidth: tamilEnabled ? 2 : 1,
          },
        },
      }}
      {...props}
    />
  );
};

export default TranslatableTextField;



