import React, { useState, useEffect } from 'react';
import { ThemeProvider, createTheme, CssBaseline } from '@mui/material';
import { Snackbar, Alert } from '@mui/material';
import './App.css';
import { initializePramukhIME } from './utils/tamilTransliteration';
import MainMenu from './components/MainMenu';
import NewRecordForm from './components/NewRecordForm';
import EditProfile from './components/EditProfile';
import ProfileView from './components/ProfileView';
import SearchPage from './components/SearchPage';
import YearlyReport from './components/YearlyReport';
import BackupRestore from './components/BackupRestore';

const theme = createTheme({
  typography: {
    fontFamily: '"Noto Sans Tamil", sans-serif',
  },
  palette: {
    primary: {
      main: '#1976d2',
    },
    secondary: {
      main: '#dc004e',
    },
    background: {
      default: '#f5f5f5',
    },
  },
});

function App() {
  const [currentPage, setCurrentPage] = useState('main');
  const [previousPage, setPreviousPage] = useState('main');
  const [selectedProfile, setSelectedProfile] = useState(null);
  const [snackbar, setSnackbar] = useState({ open: false, message: '', severity: 'success' });

  useEffect(() => {
    // Wait for pramukhIME to be loaded
    const checkAndInit = () => {
      if (window.pramukhIME) {
        console.log('PramukhIME script loaded, initializing...');
        initializePramukhIME();
      } else {
        console.log('Waiting for pramukhIME to load...');
        setTimeout(checkAndInit, 100);
      }
    };
    
    checkAndInit();
  }, []);

  const handleShowSnackbar = (message, severity = 'success') => {
    setSnackbar({ open: true, message, severity });
  };

  const handleCloseSnackbar = () => {
    setSnackbar({ ...snackbar, open: false });
  };

  const navigate = (page, profile = null) => {
    // Track previous page before navigating
    if (currentPage !== page) {
      setPreviousPage(currentPage);
    }
    setCurrentPage(page);
    setSelectedProfile(profile);
  };

  const renderPage = () => {
    switch (currentPage) {
      case 'main':
        return <MainMenu onNavigate={navigate} />;
      case 'new':
        return (
          <NewRecordForm
            onNavigate={navigate}
            onShowSnackbar={handleShowSnackbar}
          />
        );
      case 'edit':
        return (
          <EditProfile
            profile={selectedProfile}
            onNavigate={navigate}
            onShowSnackbar={handleShowSnackbar}
          />
        );
      case 'view':
        return (
          <ProfileView
            profileId={selectedProfile?.ProfileID || selectedProfile}
            onNavigate={navigate}
            onShowSnackbar={handleShowSnackbar}
            previousPage={previousPage}
          />
        );
      case 'search':
        return <SearchPage onNavigate={navigate} />;
      case 'report':
        return <YearlyReport onNavigate={navigate} />;
      case 'backup':
        return (
          <BackupRestore
            onShowSnackbar={handleShowSnackbar}
            onNavigate={navigate}
          />
        );
      default:
        return <MainMenu onNavigate={navigate} />;
    }
  };

  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <div className="app-container">
        {renderPage()}
      </div>
      <Snackbar
        open={snackbar.open}
        autoHideDuration={6000}
        onClose={handleCloseSnackbar}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
      >
        <Alert onClose={handleCloseSnackbar} severity={snackbar.severity} sx={{ width: '100%' }}>
          {snackbar.message}
        </Alert>
      </Snackbar>
    </ThemeProvider>
  );
}

export default App;

