import React, { useState, useEffect, useRef } from 'react';
import { TextField } from '@mui/material';
import { enablePramukhIME, disablePramukhIME } from '../utils/tamilTransliteration';

const TamilTextField = ({ label, value, onChange, helperText, ...props }) => {
  const [tamilEnabled, setTamilEnabled] = useState(true); // Always enabled by default
  const inputRef = useRef(null);

  useEffect(() => {
    // Small delay to ensure ref is set and element is in DOM
    const timer = setTimeout(() => {
      if (inputRef.current) {
        // Material-UI's inputRef should point to input, but verify
        let actualInput = inputRef.current;
        
        // If it's not an input element, find the input inside
        if (actualInput.tagName !== 'INPUT') {
          actualInput = actualInput.querySelector?.('input') || actualInput;
        }
        
        // Verify it's an input element (has setSelectionRange method)
        if (actualInput && typeof actualInput.setSelectionRange === 'function') {
          if (tamilEnabled) {
            console.log('Enabling IME on input element:', actualInput);
            enablePramukhIME(actualInput);
          } else {
            disablePramukhIME(actualInput);
          }
        } else {
          console.warn('Element is not a valid input:', actualInput, 'Has setSelectionRange:', typeof actualInput?.setSelectionRange);
        }
      }
    }, 100);
    
    return () => clearTimeout(timer);
  }, [tamilEnabled]);

  const handleFocus = (e) => {
    // Re-enable PramukhIME when field gains focus to ensure translation works
    const actualInput = e.target;
    if (actualInput && tamilEnabled && typeof actualInput.setSelectionRange === 'function') {
      // Small delay to ensure PramukhIME is ready
      setTimeout(() => {
        enablePramukhIME(actualInput);
      }, 50);
    }
  };

  const handleBlur = (e) => {
    // Sync the final value with React state after PramukhIME has processed it
    // This ensures values persist when switching fields
    const finalValue = e.target.value;
    if (finalValue !== value && onChange) {
      // Create a synthetic event to update React state
      onChange({ target: { value: finalValue } });
    }
  };

  return (
    <TextField
      inputRef={inputRef}
      label={label}
      value={value}
      onChange={onChange}
      onFocus={handleFocus}
      onBlur={handleBlur}
      fullWidth
      helperText={helperText || 'தமிழில் தட்டச்சு செய்ய ஆங்கிலத்தில் தட்டச்சு செய்யவும்'}
      sx={{
        '& .MuiOutlinedInput-root': {
          '&.Mui-focused fieldset': {
            borderColor: tamilEnabled ? '#1976d2' : undefined,
            borderWidth: tamilEnabled ? 2 : 1,
          },
        },
      }}
      {...props}
    />
  );
};

export default TamilTextField;



